class Solution {
public:
    int countKReducibleNumbers(string s, int k) {
        int count = 0;
        int num = stoi(s); // Convert string to integer
        for (int i = num; i >= 1; i--) {
            if (i % 2 == 0) {
                count++;
            }
        }
        return count;
    }
};
